import React, { createContext, useContext, useState, useCallback, useEffect } from "react";
import { ethers } from "ethers";

const WalletContext = createContext(null);

const TARGET_CHAIN_ID = parseInt(process.env.REACT_APP_CHAIN_ID || "31337");
const CHAIN_NAME      = process.env.REACT_APP_CHAIN_NAME || "Hardhat Local";
const RPC_URL         = process.env.REACT_APP_RPC_URL || "http://127.0.0.1:8545";
const EXPLORER_URL    = process.env.REACT_APP_EXPLORER_URL || "";

export function WalletProvider({ children }) {
  const [account,      setAccount]      = useState(null);
  const [provider,     setProvider]     = useState(null);
  const [signer,       setSigner]       = useState(null);
  const [chainId,      setChainId]      = useState(null);
  const [balance,      setBalance]      = useState(null);
  const [isConnecting, setIsConnecting] = useState(false);
  const [error,        setError]        = useState(null);

  const fetchBalance = useCallback(async (prov, addr) => {
    try {
      const bal = await prov.getBalance(addr);
      setBalance(ethers.formatEther(bal));
    } catch {
      setBalance(null);
    }
  }, []);

  const connect = useCallback(async () => {
    setError(null);
    if (!window.ethereum) {
      setError("MetaMask not found. Install it at metamask.io");
      return;
    }
    setIsConnecting(true);
    try {
      const prov = new ethers.BrowserProvider(window.ethereum);

      // Try to add/switch to the target network
      const chainHex = "0x" + TARGET_CHAIN_ID.toString(16);
      try {
        await prov.send("wallet_switchEthereumChain", [{ chainId: chainHex }]);
      } catch (switchError) {
        // Chain not added yet — add it
        if (switchError.code === 4902 || switchError?.data?.originalError?.code === 4902) {
          try {
            await prov.send("wallet_addEthereumChain", [{
              chainId: chainHex,
              chainName: CHAIN_NAME,
              rpcUrls: [RPC_URL],
              nativeCurrency: { name: "ETH", symbol: "ETH", decimals: 18 },
              ...(EXPLORER_URL ? { blockExplorerUrls: [EXPLORER_URL] } : {})
            }]);
          } catch (addError) {
            console.warn("Cannot add network:", addError);
          }
        }
      }

      const accounts = await prov.send("eth_requestAccounts", []);
      const s        = await prov.getSigner();
      const network  = await prov.getNetwork();

      setProvider(prov);
      setSigner(s);
      setAccount(accounts[0]);
      setChainId(Number(network.chainId));
      await fetchBalance(prov, accounts[0]);

      // Persist to localStorage
      localStorage.setItem("walletConnected", "true");
    } catch (e) {
      if (e.code === 4001) {
        setError("Connection rejected. Please approve in MetaMask.");
      } else {
        setError(e.message || "Failed to connect wallet.");
      }
    } finally {
      setIsConnecting(false);
    }
  }, [fetchBalance]);

  const disconnect = useCallback(() => {
    setAccount(null);
    setProvider(null);
    setSigner(null);
    setChainId(null);
    setBalance(null);
    setError(null);
    localStorage.removeItem("walletConnected");
  }, []);

  // Auto-reconnect on page load if previously connected
  useEffect(() => {
    if (localStorage.getItem("walletConnected") === "true" && window.ethereum) {
      connect();
    }
  }, [connect]);

  // Listen for MetaMask events
  useEffect(() => {
    if (!window.ethereum) return;

    const handleAccountsChanged = (accounts) => {
      if (accounts.length === 0) {
        disconnect();
      } else {
        setAccount(accounts[0]);
        if (provider) fetchBalance(provider, accounts[0]);
      }
    };

    const handleChainChanged = (chainIdHex) => {
      setChainId(parseInt(chainIdHex, 16));
      window.location.reload();
    };

    window.ethereum.on("accountsChanged", handleAccountsChanged);
    window.ethereum.on("chainChanged",    handleChainChanged);

    return () => {
      window.ethereum.removeListener("accountsChanged", handleAccountsChanged);
      window.ethereum.removeListener("chainChanged",    handleChainChanged);
    };
  }, [provider, fetchBalance, disconnect]);

  const shortAddr = account
    ? `${account.slice(0, 6)}...${account.slice(-4)}`
    : "";

  return (
    <WalletContext.Provider value={{
      account,
      provider,
      signer,
      chainId,
      balance,
      isConnecting,
      error,
      isConnected: !!account,
      connect,
      disconnect,
      shortAddress: shortAddr,
      explorerUrl: EXPLORER_URL,
      chainName: CHAIN_NAME,
      targetChainId: TARGET_CHAIN_ID,
    }}>
      {children}
    </WalletContext.Provider>
  );
}

export const useWallet = () => useContext(WalletContext);
